sp_widget.client_script:
api.controller = function($sce) {
    var c = this;

    c.decodeHTML = function(html) {
        if (!html) return "";
        return html
            .replace(/&lt;/g, "<")
            .replace(/&gt;/g, ">")
            .replace(/&amp;/g, "&")
            .replace(/&quot;/g, '"')
            .replace(/&#39;/g, "'");
    };

    c.renderHTML = function() {
        var decoded = c.decodeHTML(c.data.raw_statement);
        return $sce.trustAsHtml(decoded);
    };

		c.goBack = function () {
    window.location = '?id=incentive_statement_view';
  };

	  // ✅ initialize from server
    c.selectedUser = c.data.selectedUser;
    c.selectedPeriod = c.data.selectedPeriod;

    // OPTIONAL (if you want direct display)
    c.selectedUserName = c.data.selectedUserName;
    c.selectedPeriodName = c.data.selectedPeriodName;



};

