sp_widget.script:
(function() {

    data.statementId = $sp.getParameter("statement_id");

    if (data.statementId) {

        var grState = new GlideRecordSecure("x_ctans_incentnow_incentive_statement");
        if (grState.get($sp.getParameter("statement_id"))) {
            data.raw_statement = grState.statement + "";

            if (grState.get(data.statementId)) {

                data.raw_statement = grState.statement + "";


                // 🔹 Quota Attainment
                data.quotaAttainment = {
                    percentage: grState.quota_percentage || 0,
                    achieved: grState.quota_achieved || 0,
                    quota: grState.quota_target || 0
                };
                var quota = parseFloat(grState.getValue("target_quota")) || 0;
                var attainment = parseFloat(grState.getValue("quota_attainment")) || 0;
                data.quotaAttainment = {
                    percentage: attainment || 0,
                    quota: quota || 0,
                    achieved: parseFloat(((quota * attainment) / 100).toFixed(2))
                };
                var helper = new IncentNowStatementHelper();

                var result = helper.getQTDAndYTD(
                    grState.getValue("user"),
                    grState.getValue("plan"),
                    grState.getValue("fiscal_period")
                );
                // 🔹 QTD Commission
                data.qtdCommission = {
                    amount: result.qtd_commission,
                    transactions: 0
                };
                // 🔹 YTD Commission
                data.ytdCommission = {
                    amount: result.ytd_commission,
                    transactions: 0
                };
                var changeResult = helper.getPeriodChange(
                    grState.getValue("user"),
                    grState.getValue("plan"),
                    grState.getValue("fiscal_period")
                );
                // 🔹 Period Commission
                data.periodCommission = {
                    amount: parseFloat(grState.getValue("total_commission")) || 0,
                    change: changeResult.change_percentage + "%",
                    transactions: 0
                };


                // 🔹 Current Period
                data.currentPeriod = {
                    period: grState.period_name || "",
                    totalCommission: grState.total_commission || 0,
                    transactions: grState.total_transactions || 0
                };

            }

            // ✅ IMPORTANT: send selected values
            data.selectedUser = grState.getValue("user");
            data.selectedPeriod = grState.getValue("fiscal_period");

            // ✅ ALSO send display names (best practice)
            data.selectedUserName = grState.getDisplayValue("user");
            data.selectedPeriodName = grState.getDisplayValue("fiscal_period");
            //	}
            //		}

            var totalComm = parseFloat(grState.getValue("total_commission") || 0);


        }
    }






})();
